{"title":"Two-Column Sankey","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": "Network Flow: Source → Destination",
  "autosize": {"type": "fit", "contains": "padding"},
  "padding": 20,
  "background": "#1D1E24",
  "config": {
    "text": {"fill": "#DFE5EF"}
  },

  "signals": [
    {
      "name": "width",
      "init": "containerSize()[0]",
      "on": [{"events": {"source": "window", "type": "resize"}, "update": "containerSize()[0]"}]
    },
    {
      "name": "height",
      "init": "containerSize()[1]",
      "on": [{"events": {"source": "window", "type": "resize"}, "update": "containerSize()[1]"}]
    }
  ],

  "data": [
    {
      "name": "flows",
      "url": {
        "index": "logs-netflow.log-*",
        "body": {
          "size": 0,
          "query": {
            "bool": {
              "must": [
                {"range": {"network.bytes": {"gt": 0}}},
                {
                  "bool": {
                    "should": [
                      {"terms": {"source.ip": ["192.168.10.20", "192.168.20.100"]}},
                      {"terms": {"destination.ip": ["192.168.10.20", "192.168.20.100"]}}
                    ],
                    "minimum_should_match": 1
                  }
                }
              ]
            }
          },
          "aggs": {
            "by_flow": {
              "composite": {
                "size": 50,
                "sources": [
                  {"src": {"terms": {"field": "source.ip"}}},
                  {"dst": {"terms": {"field": "destination.ip"}}}
                ]
              },
              "aggs": {
                "total_bytes": {"sum": {"field": "network.bytes"}}
              }
            }
          }
        }
      },
      "format": {"property": "aggregations.by_flow.buckets"},
      "transform": [
        {"type": "formula", "expr": "datum.key.src", "as": "src"},
        {"type": "formula", "expr": "datum.key.dst", "as": "dst"},
        {"type": "formula", "expr": "datum.total_bytes.value || 0", "as": "bytes"}
      ]
    },
    {
      "name": "sources",
      "source": "flows",
      "transform": [
        {"type": "aggregate", "groupby": ["src"], "ops": ["sum"], "fields": ["bytes"], "as": ["total"]},
        {"type": "window", "sort": {"field": "total", "order": "descending"}, "ops": ["row_number"], "as": ["rank"]},
        {"type": "formula", "expr": "(datum.rank - 1) * (height / 4) + 50", "as": "y"}
      ]
    },
    {
      "name": "destinations",
      "source": "flows",
      "transform": [
        {"type": "aggregate", "groupby": ["dst"], "ops": ["sum"], "fields": ["bytes"], "as": ["total"]},
        {"type": "window", "sort": {"field": "total", "order": "descending"}, "ops": ["row_number"], "as": ["rank"]},
        {"type": "formula", "expr": "(datum.rank - 1) * (height / 4) + 50", "as": "y"}
      ]
    }
  ],

  "scales": [
    {
      "name": "color",
      "type": "ordinal", 
      "domain": {"data": "sources", "field": "src"},
      "range": {"scheme": "tableau20"}
    },
    {
      "name": "strokeWidth",
      "type": "linear",
      "domain": {"data": "flows", "field": "bytes"},
      "range": [1, 20]
    }
  ],

  "marks": [
    {
      "type": "group",
      "from": {
        "facet": {
          "data": "flows",
          "name": "faceted",
          "groupby": ["src", "dst", "bytes"]
        }
      },
      "marks": [
        {
          "type": "path",
          "from": {"data": "faceted"},
          "encode": {
            "enter": {
              "stroke": {"scale": "color", "signal": "parent.src"},
              "strokeWidth": {"scale": "strokeWidth", "signal": "parent.bytes"},
              "strokeOpacity": {"value": 0.4}
            },
            "update": {
              "path": {
                "signal": "'M 50,' + (data('sources')[indexof(pluck(data('sources'), 'src'), parent.src)].y) + ' C ' + (width/2) + ',' + (data('sources')[indexof(pluck(data('sources'), 'src'), parent.src)].y) + ' ' + (width/2) + ',' + (data('destinations')[indexof(pluck(data('destinations'), 'dst'), parent.dst)].y) + ' ' + (width-50) + ',' + (data('destinations')[indexof(pluck(data('destinations'), 'dst'), parent.dst)].y)"
              }
            },
            "hover": {
              "strokeOpacity": {"value": 0.8}
            }
          }
        }
      ]
    },
    {
      "type": "rect",
      "from": {"data": "sources"},
      "encode": {
        "enter": {
          "x": {"value": 30},
          "width": {"value": 20},
          "height": {"value": 20},
          "fill": {"scale": "color", "field": "src"},
          "tooltip": {"signal": "datum.src + ': ' + format(datum.total, ',.0f') + ' bytes'"}
        },
        "update": {
          "y": {"signal": "datum.y - 10"}
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "sources"},
      "encode": {
        "enter": {
          "x": {"value": 25},
          "align": {"value": "right"},
          "fontSize": {"value": 11},
          "fill": {"value": "#DFE5EF"},
          "text": {"field": "src"}
        },
        "update": {
          "y": {"signal": "datum.y + 4"}
        }
      }
    },
    {
      "type": "rect",
      "from": {"data": "destinations"},
      "encode": {
        "enter": {
          "width": {"value": 20},
          "height": {"value": 20},
          "fill": {"value": "#4dc9f6"},
          "tooltip": {"signal": "datum.dst + ': ' + format(datum.total, ',.0f') + ' bytes'"}
        },
        "update": {
           "x": {"signal": "width - 50"},
           "y": {"signal": "datum.y - 10"}
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "destinations"},
      "encode": {
        "enter": {
          "align": {"value": "left"},
          "fontSize": {"value": 11},
          "fill": {"value": "#DFE5EF"},
          "text": {"field": "dst"}
        },
        "update": {
           "x": {"signal": "width - 25"},
           "y": {"signal": "datum.y + 4"}
        }
      }
    }
  ]
}"}}

attributes.panelsJSON:
[{"type":"visualization","embeddableConfig":{"title":"Network Traffic Flows: Source ➔ Port ➔ Destination (copy)","savedVis":{"title":"Network Traffic Flows: Source ➔ Port ➔ Destination","description":"","type":"vega","params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": {
    "text": "Application Traffic (Dynamic Size)",
    "color": "#e0e0e0",
    "fontSize": 14,
    "anchor": "start",
    "offset": 10
  },

  "autosize": {"type": "fit", "contains": "padding"},
  "padding": 10,
  "background": "#1b1b24",

  "signals": [
    {
      "name": "width",
      "init": "containerSize()[0]",
      "on": [{"events": {"source": "window", "type": "resize"}, "update": "containerSize()[0]"}]
    },
    {
      "name": "height",
      "init": "containerSize()[1]",
      "on": [{"events": {"source": "window", "type": "resize"}, "update": "containerSize()[1]"}]
    }
  ],

  "data": [
    {
      "name": "rawData",
      "url": {
        "index": "logs-netflow.log-*",
        "body": {
          "size": 0,
          "query": {
            "bool": {
              "must": [
                {"range": {"network.bytes": {"gt": 0}}},
                {
                  "bool": {
                    "should": [
                      {"terms": {"source.ip": ["192.168.10.20", "192.168.20.100"]}},
                      {"terms": {"destination.ip": ["192.168.10.20", "192.168.20.100"]}}
                    ],
                    "minimum_should_match": 1
                  }
                }
              ],
              "must_not": [
                {"term": {"destination.ip": "224.0.0.5"}},
                {"term": {"destination.ip": "224.0.0.6"}},
                {"term": {"destination.port": 0}},
                {"term": {"destination.port": 2048}}
              ]
            }
          },
          "aggs": {
            "table": {
              "composite": {
                "size": 40,
                "sources": [
                  {"src": {"terms": {"field": "source.ip"}}},
                  {"port": {"terms": {"field": "destination.port"}}},
                  {"dst": {"terms": {"field": "destination.ip"}}}
                ]
              },
              "aggs": {
                "bytes": {"sum": {"field": "network.bytes"}}
              }
            }
          }
        }
      },
      "format": {"property": "aggregations.table.buckets"},
      "transform": [
        {"type": "formula", "expr": "datum.key.src", "as": "src"},
        {"type": "formula", "expr": "datum.key.dst", "as": "dst"},
        {
          "type": "formula", 
          "expr": "datum.key.port === 0 ? 'ICMP' : (datum.key.port === 5201 ? 'iPerf (5201)' : (datum.key.port === 80 ? 'HTTP (80)' : 'Port ' + datum.key.port))", 
          "as": "port"
        },
        {"type": "formula", "expr": "datum.bytes.value", "as": "size"}
      ]
    },
    {
      "name": "nodes",
      "source": "rawData",
      "transform": [
        {
          "type": "fold",
          "fields": ["src", "port", "dst"],
          "as": ["stack", "name"]
        },
        {
          "type": "aggregate",
          "groupby": ["stack", "name"],
          "ops": ["sum"],
          "fields": ["size"],
          "as": ["total"]
        },
        {
          "type": "formula",
          "expr": "datum.stack === 'src' ? 0 : (datum.stack === 'port' ? 1 : 2)",
          "as": "col"
        },
        {
          "type": "stack",
          "groupby": ["col"],
          "sort": {"field": "total", "order": "descending"},
          "field": "total"
        },
        {
          "type": "formula",
          "expr": "(datum.col * (width / 2))",
          "as": "x0"
        },
        {
          "type": "formula",
          "expr": "datum.x0 + 20",
          "as": "x1"
        }
      ]
    },
    {
      "name": "layout_nodes",
      "source": "nodes",
      "transform": [
         {
          "type": "formula",
          "expr": "scale('y', datum.y0)",
          "as": "y0_px"
         },
         {
          "type": "formula",
          "expr": "scale('y', datum.y1)",
          "as": "y1_px"
         },
         {
          "type": "formula",
          "expr": "(datum.y0_px + datum.y1_px) / 2",
          "as": "yc"
         },
         {
           "type": "formula",
           "expr": "datum.y1_px - datum.y0_px",
           "as": "height"
         }
      ]
    },
    {
      "name": "links_src_port",
      "source": "rawData",
      "transform": [
        {
          "type": "lookup",
          "from": "layout_nodes",
          "key": "name",
          "fields": ["src", "port"],
          "as": ["sourceNode", "targetNode"]
        },
        {
           "type": "linkpath",
           "orient": "horizontal",
           "shape": "diagonal",
           "sourceX": {"expr": "datum.sourceNode.x1"},
           "sourceY": {"expr": "datum.sourceNode.yc"},
           "targetX": {"expr": "datum.targetNode.x0"},
           "targetY": {"expr": "datum.targetNode.yc"}
        }
      ]
    },
    {
      "name": "links_port_dst",
      "source": "rawData",
      "transform": [
        {
          "type": "lookup",
          "from": "layout_nodes",
          "key": "name",
          "fields": ["port", "dst"],
          "as": ["sourceNode", "targetNode"]
        },
        {
           "type": "linkpath",
           "orient": "horizontal",
           "shape": "diagonal",
           "sourceX": {"expr": "datum.sourceNode.x1"},
           "sourceY": {"expr": "datum.sourceNode.yc"},
           "targetX": {"expr": "datum.targetNode.x0"},
           "targetY": {"expr": "datum.targetNode.yc"}
        }
      ]
    }
  ],

  "scales": [
    {
      "name": "y",
      "type": "linear",
      "range": [{"signal": "20"}, {"signal": "height - 20"}],
      "nice": true, "zero": true,
      "domain": {"data": "nodes", "field": "y1"}
    },
    {
      "name": "color",
      "type": "ordinal",
      "domain": {"data": "nodes", "field": "name"},
      "range": [
        "#3273dc", "#00d1b2", "#ffdd57", "#ff3860", 
        "#b86bff", "#ff9f43", "#23d160", "#5f27cd"
      ]
    },
    {
      "name": "width_scale",
      "type": "linear",
      "range": [1, 60],
      "domain": {"data": "rawData", "field": "size"}
    }
  ],

  "marks": [
    {
      "type": "path",
      "from": {"data": "links_src_port"},
      "encode": {
        "enter": {
          "path": {"field": "path"}
        },
        "update": {
          "stroke": {"scale": "color", "field": "src"},
          "strokeOpacity": {"value": 0.4},
          "strokeWidth": {"scale": "width_scale", "field": "size"},
          "zindex": {"value": 0}
        },
        "hover": {
          "strokeOpacity": {"value": 0.8},
          "stroke": {"value": "#fff"},
          "zindex": {"value": 1}
        }
      }
    },
    {
      "type": "path",
      "from": {"data": "links_port_dst"},
      "encode": {
        "enter": {
          "path": {"field": "path"}
        },
        "update": {
          "stroke": {"scale": "color", "field": "port"},
          "strokeOpacity": {"value": 0.4},
          "strokeWidth": {"scale": "width_scale", "field": "size"},
          "zindex": {"value": 0}
        },
        "hover": {
          "strokeOpacity": {"value": 0.8},
          "stroke": {"value": "#fff"},
          "zindex": {"value": 1}
        }
      }
    },
    {
      "type": "rect",
      "from": {"data": "layout_nodes"},
      "encode": {
        "enter": {
          "x": {"field": "x0"},
          "x2": {"field": "x1"},
          "y": {"field": "y0_px"},
          "y2": {"field": "y1_px"},
          "fill": {"scale": "color", "field": "name"},
          "cornerRadius": {"value": 2},
          "tooltip": {"signal": "datum.name + ': ' + format(datum.total, '.2s') + 'B'"}
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "layout_nodes"},
      "encode": {
        "enter": {
          "x": {"signal": "datum.col === 0 ? datum.x1 + 8 : (datum.col === 2 ? datum.x0 - 8 : datum.x1 + 8)"},
          "y": {"field": "yc"},
          "text": {"signal": "datum.height > 12 ? datum.name : ''"},
          "align": {"signal": "datum.col === 2 ? 'right' : 'left'"},
          "baseline": {"value": "middle"},
          "fill": {"value": "#f5f5f5"},
          "fontSize": {"value": 11}
        }
      }
    },
    {
      "type": "text",
      "encode": {
        "enter": {
          "x": {"value": 0}, "y": {"value": 10},
          "text": {"value": "SOURCE"}, "fill": {"value": "#888"}, "fontWeight": {"value": "bold"}
        }
      }
    },
    {
      "type": "text",
      "encode": {
        "enter": {
          "x": {"signal": "width / 2"}, "y": {"value": 10},
          "text": {"value": "PORT"}, "fill": {"value": "#888"}, "fontWeight": {"value": "bold"}
        }
      }
    },
    {
      "type": "text",
      "encode": {
        "enter": {
          "x": {"signal": "width"}, "y": {"value": 10},
          "text": {"value": "DESTINATION"}, "align": {"value": "right"}, "fill": {"value": "#888"}, "fontWeight": {"value": "bold"}
        }
      }
    }
  ]
}"},"uiState":{},"data":{"aggs":[],"searchSource":{"query":{"query":"","language":"kuery"},"filter":[]}}}},"panelIndex":"5ed0f2d3-099a-4069-9905-53539bed5587","gridData":{"y":35,"x":0,"w":22,"h":26,"i":"5ed0f2d3-099a-4069-9905-53539bed5587"}},{"type":"lens","embeddableConfig":{"title":"Source to Destination Traffic","syncColors":false,"syncCursor":true,"syncTooltips":false,"filters":[],"query":{"esql":"FROM logs-netflow.log-default
