                  }
                }
              }
            }
          }
        }
      },
      "format": { "property": "aggregations.by_router.buckets" },
      "transform": [
        { "type": "formula", "as": "router_id", "expr": "datum.key" },
        { "type": "flatten", "fields": ["by_interface.buckets"], "as": ["iface"] },
