        { "type": "formula", "as": "admin_status", "expr": "datum.iface.latest.hits.hits[0]._source.network.interface.admin.status" },
        { "type": "formula", "as": "is_admin_up", "expr": "datum.admin_status == 1 ? 1 : 0" },
