      ]
    },
    {
      "name": "router_interface_stats",
      "source": "snmp_interfaces",
      "transform": [
        {
          "type": "aggregate",
          "groupby": ["router_id"],
          "ops": ["sum", "sum"],
          "fields": ["is_admin_up", "is_oper_up"],
          "as": ["admin_up_count", "oper_up_count"]
        }
      ]
    },
    {
      "name": "lldp_raw",
      "url": {
        "index": "net-lldp-edges",
        "body": {
          "size": 200,
          "query": { "range": { "last_seen": { "gte": "now-5m" } } }
